void matrix_multiply_36(float A[3][6], float B[6][3], float result[3][3]) {
    int i, j, k;

    for (i = 0; i < 3; i++) {
        for (j = 0; j < 3; j++) {
            result[i][j] = 0;
            for (k = 0; k < 6; k++) {
                result[i][j] += A[i][k] * B[k][j];
            }
        }
    }
}

void matrix_multiply_63(float A[6][3], float B[3][3], float result[6][3]) {
    int i, j, k;

    for (i = 0; i < 6; i++) {
        for (j = 0; j < 3; j++) {
            result[i][j] = 0;
            for (k = 0; k < 3; k++) {
                result[i][j] += A[i][k] * B[k][j];
            }
        }
    }
}

void matrix_multiply_6(float A[6][3], float B[3], float result[6]) {
    int i, j;

    for (i = 0; i < 6; i++) {
    result[i] = 0;
        for (j = 0; j < 3; j++) {
            result[i] += A[i][j] * B[j];
        }
    }
    
}

void transpose_matrix(float matrix[3][6], float transpose[6][3]) {
    int i, j;

    for (i = 0; i < 3; i++) {
        for (j = 0; j < 6; j++) {
            transpose[j][i] = matrix[i][j];
        }
    }
}

void inverse_matrix_33(float a[3][3], float a_inv[3][3]){
	int i, j, k;
	float determinant = 0;
	
	for(i = 0; i < 3; i++)
        determinant = determinant + (a[0][i]*(a[1][(i+1)%3]*a[2][(i+2)%3] - a[1][(i+2)%3]*a[2][(i+1)%3]));
 
   	if(determinant == 0){
   		determinant = 0.1;
	}
	
    for(i = 0; i < 3; i++){
        for(j=0; j < 3; j++)
            a_inv[i][j] = (((a[(i+1)%3][(j+1)%3] * a[(i+2)%3][(j+2)%3]) - (a[(i+1)%3][(j+2)%3]*a[(i+2)%3][(j+1)%3]))/ determinant);
    }
    
    
}



