void trajectory_line(float t){
	static float xRobot_init, yRobot_init, zRobot_init, x_cmd, y_cmd, z_cmd;
	static int linemode = 0;
	
	if(t<=dt){
		xRobot_init = fkine_x;
		yRobot_init = fkine_y;
		zRobot_init = fkine_z;
		
		linemode=(linemode==1)?0:1;
		if(linemode == 0){
			x_cmd = 1.4951;
			y_cmd = -0.5506;
			z_cmd = 0.446;
		} else {
			x_cmd = 1.2457;
			y_cmd = 0.50044;
			z_cmd = 1.645;
		}

	}
	
	if(t<= time_traj){
		tra_x = (x_cmd - xRobot_init)*t/time_traj + xRobot_init;
		tra_y = (y_cmd - yRobot_init)*t/time_traj + yRobot_init;
		tra_z = (z_cmd - zRobot_init)*t/time_traj + zRobot_init;
		
	}
	

}

